// ============================================
// BOLIGFLOW EMAIL TEMPLATE
// Claude: Modify the data extraction, filtering, and table columns
// to match the user's request. Keep the HTML structure and branding.
// ============================================

const response = $input.all()[0].json;
// Check for GraphQL errors
if (response.errors) {
  throw new Error('GraphQL error: ' + response.errors.map(e => e.message).join(', '));
}


// --- DATA EXTRACTION (modify query path as needed) ---
const items = response.data?.leaseAgreements?.data || [];

// --- FILTERING (add/change filters based on user request) ---
const filtered = items;

// --- TABLE ROWS (change columns to match the data) ---
let rows = '';
for (const item of filtered) {
  const lease = item.lease || {};
  const address = lease.fullAddress || 'Ukendt adresse';
  const leaseId = lease.id || '';
  const startDate = lease.currentOrNextLeaseAgreement?.startDate || '-';

  rows += `
    <tr>
      <td style="padding:8px; border-bottom:1px solid #eee;">
        <a style="color:#15847F;" href="https://app.boligflow.dk/leases/${leaseId}">${address}</a>
      </td>
      <td style="padding:8px; border-bottom:1px solid #eee;">${startDate}</td>
    </tr>`;
}

// --- EMAIL TITLE (change to match context) ---
const title = 'Oversigt';
const subtitle = `Der er ${filtered.length} resultater:`;

// --- TABLE HEADERS (match the columns above) ---
const headers = `
  <th style="text-align:left; padding:8px;">Adresse</th>
  <th style="text-align:left; padding:8px;">Dato</th>`;

// ============================================
// HTML TEMPLATE - DO NOT MODIFY BELOW
// ============================================
const html = `
<table width="100%" cellspacing="0" cellpadding="0" style="font-family:'lucida sans unicode','lucida grande',sans-serif;">
  <tr>
    <td align="center" style="padding:20px;">
      <img src="https://demo.stripocdn.email/content/guids/497a0606-5367-460f-9c9c-8a0b17a753ad/images/image.png" width="180">
    </td>
  </tr>
  <tr>
    <td style="padding:20px;">
      <h3 style="color:#15847F;">${title}</h3>
      <p>${subtitle}</p>
      <table width="100%" cellspacing="0" cellpadding="0" style="border-collapse:collapse;">
        <tr style="background:#15847F; color:#fff;">
          ${headers}
        </tr>
        ${rows}
      </table>
    </td>
  </tr>
</table>`;

return [{ json: { html } }];
